graphql.query:
query getRoutePresetsById($id: UUID!) {
  waybills_routePresets(clientId: $id) {
    clientId
    createdAt
    id
    isDefault
    name
    presetWarehouses {
      id
      isRequired
      defaultStorageTime
      position
      type {
        id
        nameEn
        nameRu
        __typename
      }
      warehouse {
        id
        name
        type {
          id
          nameEn
          nameRu
          __typename
        }
        __typename
      }
      __typename
    }
    __typename
  }
}

query getDefaultRoutePresetById($id: UUID!) {
  waybills_routePresetDefault(clientId: $id) {
    id
    name
    clientId
    isDefault
    createdAt
    presetWarehouses {
      defaultStorageTime
      id
      isRequired
      position
      type {
        id
        nameEn
        nameRu
        __typename
      }
      warehouse {
        id
        name
        type {
          id
          nameEn
          nameRu
          __typename
        }
        __typename
      }
      __typename
    }
    __typename
  }
}
